function extractMentions(text) {
  const matches = text.match(/\b([A-Z][a-z]+(?: [A-Z][a-z]+){1,3})\b/g) || [];
  return [...new Set(matches)].slice(0, 4);
}

// Bayesian confidence: source_credibility * recency_decay
// corroboration_factor starts at 1.0 (graph will update as more sources confirm)
function computeConfidence(sourceCred, pubDate) {
  const now = Date.now();
  const pub = pubDate ? new Date(pubDate).getTime() : now;
  const ageHours = Math.max(0, (now - pub) / 3600000);
  const recencyDecay = Math.exp(-0.02 * ageHours); // half-life ~35 hours
  return Math.round(sourceCred * recencyDecay * 100) / 100;
}

for (const item of items) {
  const a = item.json;
  if (!a || typeof a !== 'object' || !a.title || !a.source) continue;

  const title = String(a.title).trim().substring(0, 200);
  const category = a.category || 'world_news';
  const source = a.source;
  const url = a.link || a.url || '';
  const published = a.pubDate || a.isoDate || new Date().toISOString();
  const causal_weight = typeof a.causal_weight === 'number' ? a.causal_weight : 0.3;
  const mechanism = a.mechanism || 'news_signal';
  const source_credibility = typeof a.source_credibility === 'number' ? a.source_credibility : 0.7;

  const description = String(a.content || a.contentSnippet || a.summary || '')
    .replace(/<[^>]*>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .substring(0, 600);

  const entityType = TYPE_MAP[category] || 'political_event';
  const confidence = computeConfidence(source_credibility, published);

  const relationships = [{
    targetName: source,
    targetType: 'company',
    targetProperties: { domain: 'media', category },
    relation: 'cited_by',
    confidence: 0.95,
    causal_weight: 0.1,
    mechanism: 'media_attribution'
  }];

  const mentions = extractMentions(title + ' ' + description.substring(0, 200));
  for (const mention of mentions) {
    relationships.push({
      targetName: mention,
      targetType: 'person',
      relation: 'related_to',
      confidence: 0.4,
      causal_weight: causal_weight * 0.5,
      mechanism
    });
  }

  results.push({ json: {
    name: title,
    type: entityType,
    properties: {
      url,
      description: description.substring(0, 500),
      category,
      published,
      source_credibility,
      provenance: [source],
      valid_from: published
    },
    relationships,
    source,
    confidence,
    causal_weight,
    mechanism,
    // Pass full text for LLM causal extraction downstream
    _raw_text: (title + '. ' + description).substring(0, 1500)
  }});
}

return results.length > 0 ? results : [{
  json: {
    name: 'empty', type: 'political_event', source: 'system',
    properties: {}, relationships: [], confidence: 0,
    causal_weight: 0, mechanism: 'none', _empty: true
  }
}];

