          mechanism:        { type: 'string', description: 'Short causal mechanism label' },
          evidence_span:    { type: 'string', description: 'Exact quote from text supporting this causal claim' }
        }
      }
    },
    abstain: { type: 'boolean', description: 'Set true if no causal relationship can be identified' }
  },
  required: ['causal_triples', 'abstain']
};

const OPENAI_BASE = 'https://api.openai.com/v1';
const API_KEY = $env.OPENAI_API_KEY || '';

async function extractCausal(text, entityName) {
  if (!API_KEY || !text || text.length < 50) return null;

  const prompt = `You are a causal intelligence analyst. Extract causal relationships from the following news text.

Rules:
- Only extract relationships where one entity or event CAUSES or significantly influences another
- Do NOT extract mere co-occurrence or correlation
- For each causal triple, cite the exact text span that supports it
- If no clear causal relationship exists, set abstain=true and return empty causal_triples array
- attribution_type: "clear" = direct stated causation, "indirect" = implied through mechanism, "ambiguous" = uncertain

Text: "${text.substring(0, 1200)}"

Respond ONLY with valid JSON matching the schema. No explanation.`;

  try {
    const resp = await $http.request({
      method: 'POST',
      url: `${OPENAI_BASE}/chat/completions`,
      headers: {
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'gpt-4.1-mini',
        messages: [{ role: 'user', content: prompt }],
        response_format: { type: 'json_object' },
        max_tokens: 600,
        temperature: 0.1
      })
    });

    const raw = resp.choices?.[0]?.message?.content;
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (parsed.abstain || !Array.isArray(parsed.causal_triples)) return null;
    return parsed.causal_triples.filter(t =>
      t.cause && t.effect && t.attribution_type && typeof t.causal_weight === 'number'
    );
  } catch (e) {
    return null;
  }
}

for (const item of items) {
