        evidence_span: t.evidence_span?.substring(0, 300) || ''
      });
    }
  }

  // Remove internal _raw_text before sending to graph
  const { _raw_text, ...cleanEntity } = a;
  results.push({ json: { ...cleanEntity, relationships: enrichedRelationships } });
}

